#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 100001
typedef struct Node {
    int data;
    struct Node* next;
} Node;
Node* createNode(int data) {
    Node* newNode = (Node*) malloc(sizeof(Node));
    if (!newNode) {
        printf("Memory error\n");
        return NULL;
    }
    newNode->data = data;
    newNode->next = NULL;
    return newNode;
}
void insertEdge(Node** adj, int src, int dest) {
    Node* newNode = createNode(dest);
    newNode->next = adj[src];
    adj[src] = newNode;
}
int bfs(Node** adj, int src, int dest, int n) {
    int* visited = (int*) calloc(n + 1, sizeof(int));
    int* distance = (int*) calloc(n + 1, sizeof(int));
    Node* queue = createNode(src);
    Node* temp = queue;
    visited[src] = 1;
    distance[src] = 0;
    while (temp) {
        Node* neighbor = adj[temp->data];
        while (neighbor) {
            if (!visited[neighbor->data]) {
                visited[neighbor->data] = 1;
                distance[neighbor->data] = distance[temp->data] + 1;
                Node* newNode = createNode(neighbor->data);
                newNode->next = queue;
                queue = newNode;
            }
            neighbor = neighbor->next;
        }
        temp = temp->next;
    }
    int dist = distance[dest];
    free(visited);
    free(distance);
    return dist;
}
int main() {
    int n;
    scanf("%d", &n);
    Node** adj = (Node**) malloc(n + 1 * sizeof(Node*));
    for (int i = 0; i <= n; i++) {
        adj[i] = NULL;
    }
    for (int i = 0; i < n - 1; i++) {
        int u, v;
        scanf("%d %d", &u, &v);
        insertEdge(adj, u, v);
        insertEdge(adj, v, u);
    }
    int q;
    scanf("%d", &q);
    for (int i = 0; i < q; i++) {
        int u, v;
        scanf("%d %d", &u, &v);
        printf("%d\n", bfs(adj, u, v, n));
    }
    return 0;
}

