#include <iostream>
#include <vector>
#include <queue>
using namespace std;
#define MAX 100001
vector<int> adj[MAX];
int bfs(int src, int dest, int n) {
    vector<bool> visited(n + 1, false);
    vector<int> distance(n + 1, 0);
    queue<int> q;
    q.push(src);
    visited[src] = true;
    while (!q.empty()) {
        int temp = q.front();
        q.pop();
        for (int neighbor : adj[temp]) {
            if (!visited[neighbor]) {
                visited[neighbor] = true;
                distance[neighbor] = distance[temp] + 1;
                q.push(neighbor);
            }
        }
    }
    return distance[dest];
}
